module SRAM_Cell(  
    input [7:0] data_in,  
    input we,  
    output reg [7:0] data_out  
);  
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};

    reg [7:0] memory;  

    always @(posedge we) begin  
        memory <= data_in;  
    end  

    always @(*) begin  
        data_out = memory;  
    end  
endmodule
